INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Email marketing and autoresponders$q$, $q$Drag-and-drop email builder with templates, unlimited monthly sends on paid plans, and automated autoresponder sequences.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Marketing automation$q$, $q$Visual workflow builder for behavior-based automations, cart abandonment recovery, and multi-step customer journeys.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Landing pages and websites$q$, $q$Built-in landing page and simple website builder with signup forms, no separate hosting required.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Conversion funnels$q$, $q$Pre-built sales and lead-generation funnel templates for e-commerce and digital product sales.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Webinars$q$, $q$Native webinar hosting for live and on-demand sessions, supporting up to 100 attendees on the Creator plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Course creator$q$, $q$Tools for building and selling online courses directly from the platform, including student management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$AI content generation$q$, $q$AI-assisted tools for writing subject lines, email copy, and full campaigns.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$SMS and push notifications$q$, $q$SMS marketing credits and unlimited web push notifications on higher-tier plans for multichannel outreach.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Genuinely usable free plan and 30-day free trial with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Broad all-in-one feature set (email, funnels, webinars, courses) reduces need for separate tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Strong deliverability reputation and two decades of email infrastructure experience$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Competitive pricing relative to the breadth of included features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$E-commerce integrations with Shopify, WooCommerce, and other major platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Automation builder and reporting are less advanced than dedicated enterprise platforms like HubSpot or Marketo$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Interface and template design can feel dated compared to newer competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Pricing scales quickly as contact list size grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Some advanced features (custom IP, dedicated account management) are locked behind the custom-priced Enterprise tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Free plan is limited enough that most serious users will need to upgrade quickly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Is GetResponse free to use?$q$, $q$GetResponse offers a free plan with limited contacts and features, plus a 30-day free trial of paid plans that does not require a credit card.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$How much does GetResponse cost?$q$, $q$Paid plans start around $19 per month for the Starter tier on a small contact list, with Marketer and Creator tiers priced higher, and a custom-priced Enterprise/Max plan for large organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Who founded GetResponse?$q$, $q$GetResponse was founded by Simon Grabowski in Gdansk, Poland, originally launched around 1997-1998 as an email automation script for his own travel listings business.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Does GetResponse include landing pages and webinars?$q$, $q$Yes, landing pages and signup forms are included on all paid plans, and webinar hosting is available starting on the Creator plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$What are the main alternatives to GetResponse?$q$, $q$Common alternatives include Mailchimp, ActiveCampaign, Klaviyo, Constant Contact, and Brevo, depending on whether the buyer prioritizes e-commerce, automation depth, or price.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Does GetResponse support e-commerce and abandoned cart recovery?$q$, $q$Yes, GetResponse integrates with major e-commerce platforms and includes abandoned cart recovery, promo codes, and revenue reporting starting on the Marketer plan.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Small business email marketing$q$, $q$Running newsletters, promotions, and automated welcome sequences for a growing customer list.$q$, $q$Small business owners and solo marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$E-commerce conversion funnels$q$, $q$Building abandoned cart recovery flows and sales funnels integrated with Shopify or WooCommerce stores.$q$, $q$Online retailers and e-commerce teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Course and webinar delivery$q$, $q$Hosting webinars and selling online courses directly through the platform without third-party tools.$q$, $q$Coaches, consultants, and independent educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Limited contacts","Basic email sending","Website builder","1 user"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Starter$q$, $q$From $19/month$q$, $q$Monthly or annual (annual discount ~18%)$q$, NULL, $q$["Unlimited monthly email sends","Limited AI content generation","1 automation workflow","Landing pages and signup forms","Up to 3 users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Marketer$q$, $q$From $54/month$q$, $q$Monthly or annual (annual discount ~18%)$q$, NULL, $q$["Unlimited automation workflows","Advanced segmentation","Abandoned cart recovery and sales funnels","Promo codes and revenue reports","Unlimited web push notifications","Up to 5 users"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Creator$q$, $q$From $62/month$q$, $q$Monthly or annual (annual discount ~18%)$q$, NULL, $q$["All Marketer features","Course creator (up to ~500 students)","Premium newsletter subscriptions","Website builder","Webinars up to 100 attendees","Up to 5 users"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Enterprise / Max$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["All lower-tier features","SMS marketing credits","Mobile push notifications","Dedicated sending domain and IP","Dedicated customer experience manager","Phone and Slack support","Unlimited users"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GetResponse is an all-in-one online marketing platform built around email marketing and automation, founded in Poland in 1998 by Simon Grabowski, who still leads the company as CEO.$q$, $q$Over more than two decades the product has expanded from simple autoresponders into a broader suite covering landing pages, conversion funnels, webinars, paid newsletters, course creation, and AI-assisted content tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core is a drag-and-drop email builder paired with a visual marketing automation workflow editor that supports conditional branching based on subscriber behavior.$q$, $q$Additional modules cover landing pages, e-commerce conversion funnels, webinars, SMS and web push notifications, a course creator, and paid newsletter subscriptions, making it a genuine multi-tool platform rather than a single-purpose email sender.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GetResponse offers a free plan for very small lists plus four paid tiers, Starter, Marketer, Creator, and a custom-priced Enterprise/Max plan, priced primarily by contact list size and feature access.$q$, $q$Annual billing brings roughly an 18% discount versus monthly billing, and every paid tier includes unlimited monthly email sends regardless of list size.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Native email newsletters$q$, $q$Built-in email sending and subscriber management so newsletters go out directly from the platform without a separate ESP.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Paid memberships and subscriptions$q$, $q$Stripe-integrated paid tiers and member-only content gating built into core, not a plugin add-on.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Markdown and blocks editor$q$, $q$A distraction-free writing editor supporting Markdown shortcuts and rich content blocks (images, galleries, embeds, bookmarks).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Headless/API-first architecture$q$, $q$A JSON content API allows developers to build custom frontends in frameworks like Next.js or Astro on top of Ghost.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Theme marketplace$q$, $q$Official and third-party Handlebars-based themes for customizing site design without touching core code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Built-in SEO tools$q$, $q$Automatic sitemaps, structured data, and meta field controls tuned for publishing and discoverability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Multi-newsletter support$q$, $q$Higher tiers support multiple distinct newsletters from a single site for segmented audiences.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Self-hosting option$q$, $q$The full open-source codebase can be self-hosted for free, giving complete control over infrastructure and data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Fully open source (MIT license) with a free self-hosting option and no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Native paid membership and newsletter monetization without needing extra plugins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Nonprofit governance structure makes the platform structurally resistant to acquisition or shutdown$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Lean, fast, publishing-focused architecture compared to general-purpose CMS platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Headless API supports fully custom frontends for developer teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Less flexible than WordPress for building non-publishing websites (e-commerce stores, complex layouts)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Self-hosting requires technical setup and ongoing maintenance (Node.js, database, email deliverability)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Ghost(Pro) Business and Enterprise tiers are considerably pricier than many newsletter-only competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Smaller plugin/theme ecosystem than WordPress$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Member limits on lower Ghost(Pro) tiers can require upgrading as an audience grows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Is Ghost free to use?$q$, $q$The Ghost open-source software is free to self-host under the MIT license; the managed Ghost(Pro) hosting service is a paid subscription starting at $18/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Who created Ghost?$q$, $q$Ghost was created by John O'Nolan and Hannah Wolfe, launching publicly in October 2013 after a Kickstarter campaign that raised over 196,000 pounds.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Is Ghost owned by a company that could be acquired?$q$, $q$No. Ghost is run by the nonprofit Ghost Foundation, which has no shareholders and is legally structured so it cannot be bought or sold.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Can Ghost handle paid newsletters and memberships?$q$, $q$Yes, Ghost has native, built-in support for paid subscription tiers and member-only content via a direct Stripe integration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$How is Ghost different from WordPress?$q$, $q$Ghost is a leaner, publishing-and-newsletter-focused platform with native memberships, while WordPress is a more general-purpose CMS with a much larger plugin ecosystem.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Can Ghost be used headless with a custom frontend?$q$, $q$Yes, Ghost exposes a JSON content API that developers can use to power custom frontends built in frameworks like Next.js, Astro, or Gatsby.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Independent newsletter publishing$q$, $q$Writing and monetizing a paid email newsletter with native subscription billing.$q$, $q$Independent writers and journalists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Membership media sites$q$, $q$Running a publication with multiple paid membership tiers and gated content.$q$, $q$Media companies and content businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Developer-built headless blogs$q$, $q$Using Ghost as an API-driven content backend behind a custom-built frontend.$q$, $q$Development teams building custom publishing experiences$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Self-hosted (open source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Ghost core codebase","MIT license","Self-managed infrastructure and email sending","Unlimited members and staff (self-managed)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Starter (Ghost(Pro))$q$, $q$$18/month$q$, $q$Billed yearly$q$, NULL, $q$["1 staff user","5MB file uploads","Up to 1,000 members","Free custom domain","Unlimited email sends"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Publisher (Ghost(Pro))$q$, $q$$29/month$q$, $q$Billed yearly$q$, NULL, $q$["3 staff users","100MB file uploads","Up to 1,000 members","Marketplace themes","Paid subscriptions, up to 3 newsletters","Advanced analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Business (Ghost(Pro))$q$, $q$$199/month$q$, $q$Billed yearly$q$, NULL, $q$["15 staff users","250MB file uploads","Up to 10,000 members","Priority support","Up to 10 premium tiers, 50 promotional offers"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$Custom (Ghost(Pro))$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["Unlimited staff users","1GB file uploads","Unlimited members","Dedicated IP and uptime SLA","Single sign-on","Dedicated account manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ghost is an open-source publishing platform for blogs, newsletters, and paid membership sites, created by John O'Nolan and Hannah Wolfe and funded by a record-setting 2013 Kickstarter campaign.$q$, $q$The project is now run by the nonprofit Ghost Foundation, registered in Singapore, which has no external shareholders and is structurally protected against acquisition, funding itself entirely through the managed Ghost(Pro) hosting service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ghost includes a native Markdown-and-blocks editor, built-in email newsletter delivery, and Stripe-powered paid membership tiers without requiring third-party plugins.$q$, $q$Its headless-capable JSON content API lets developers build fully custom frontends while Ghost handles publishing, subscriber, and payment logic in the background.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source core is free to self-host on your own infrastructure under the MIT license.$q$, $q$Ghost(Pro) managed hosting starts at $18 per month for the Starter tier and scales through Publisher ($29/month), Business ($199/month), and a custom-priced Enterprise tier, all billed yearly for the listed rates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
