INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079eef6a-7551-42f9-8218-0e4c4e82dc10', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Multi-asset portfolio tracking$q$, $q$Tracks stocks, ETFs, mutual funds, cryptocurrencies, and manually defined custom assets in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Net worth dashboard$q$, $q$Consolidates holdings from multiple accounts and platforms into a single net-worth view over time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Transaction management$q$, $q$Create, edit, import, and export investment activity and transaction history.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Performance charts$q$, $q$Historical performance visualization across standard timeframes (1D, 1W, YTD, 1Y, max, etc.).$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Static risk analysis$q$, $q$Portfolio concentration breakdown by sector, region, and asset class.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$REST API access$q$, $q$Programmatic API for building custom integrations or automating data imports.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Self-hosted deployment$q$, $q$Full Docker-based self-hosting option running the complete open-source codebase with no feature gating.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Privacy-first design$q$, $q$No ad-based monetization or data resale; self-hosted data never leaves the user's own infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Genuinely free, fully-featured self-hosted option under an open-source license (AGPL-3.0)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Strong privacy posture with no ads and no third-party data sales$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Modern, well-documented tech stack (Angular, NestJS, Prisma) that's approachable for developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Active open-source community and regularly shipped updates$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Consolidates multiple asset classes (stocks, ETFs, crypto) in a single dashboard$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Self-hosting requires technical comfort with Docker and server maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Solo-founder-led project means smaller support team than venture-backed competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$No multi-tenant or advisor/white-label mode for professional wealth managers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Some premium market-data sources are limited to the paid cloud tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Community/GitHub-based support rather than dedicated customer service$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Is Ghostfolio free?$q$, $q$Yes, the self-hosted version of Ghostfolio is completely free and open source under the AGPL-3.0 license; a managed cloud subscription (Ghostfolio Premium) is available for around $40/year.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Who created Ghostfolio?$q$, $q$Ghostfolio was created by Thomas Kaul, a Swiss software engineer based in Zurich, starting around 2021.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$What tech stack does Ghostfolio use?$q$, $q$Ghostfolio is built with an Angular frontend, a NestJS backend, Prisma as its ORM, PostgreSQL as its database, and Nx to manage the monorepo.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Can Ghostfolio track cryptocurrency alongside stocks?$q$, $q$Yes, Ghostfolio supports tracking stocks, ETFs, mutual funds, cryptocurrencies, and custom manually-defined assets together in one portfolio.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Does Ghostfolio have an API?$q$, $q$Yes, Ghostfolio exposes a REST API that can be used to automate imports or build custom integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$What license is Ghostfolio released under?$q$, $q$Ghostfolio's source code is released under the GNU Affero General Public License v3 (AGPL-3.0).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Self-hosted net worth tracking$q$, $q$Running Ghostfolio on a home server or VPS to track investments without third-party data sharing.$q$, $q$Privacy-conscious self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Multi-broker portfolio consolidation$q$, $q$Combining holdings from several brokerage and exchange accounts into a single dashboard.$q$, $q$Individual investors with accounts across multiple platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Developer-driven finance automation$q$, $q$Using the REST API to automate transaction imports or build custom financial reporting.$q$, $q$Developers and technically-inclined investors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Self-hosted (open source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase (AGPL-3.0)","Self-managed Docker deployment","Unlimited accounts and transactions","Community support via GitHub/Discord"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$Ghostfolio Premium (cloud)$q$, $q$About $40/year$q$, $q$Annual (monthly option available)$q$, NULL, $q$["Fully managed hosting","Automatic backups and maintenance","Access to professional market-data providers","No server setup required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ghostfolio is an open-source portfolio and net-worth tracker created by Zurich-based developer Thomas Kaul around 2021, released under the AGPL-3.0 license.$q$, $q$It can be self-hosted for free using its Angular/NestJS/Prisma stack, or accessed via the managed Ghostfolio Premium cloud subscription for users who don't want to run their own server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ghostfolio consolidates stocks, ETFs, mutual funds, cryptocurrencies, and custom assets across multiple accounts into a single net-worth dashboard with historical performance charts.$q$, $q$It also provides transaction import/export, a static risk-analysis view by sector and region, and a REST API for building custom integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted core application is entirely free under the AGPL-3.0 license, with users covering only their own server hosting costs.$q$, $q$Ghostfolio Premium, the managed cloud version, costs roughly $40 per year and includes hosting, maintenance, and access to professional market-data providers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94821a2d-fb17-42ea-8e5e-a593d22a6841', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Student information management$q$, $q$Central student records with a Fast Student Finder tool for quickly surfacing academic, behavioral, medical, and SEN alerts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Attendance tracking$q$, $q$Attendance recording for form groups or individual students, with historical pattern views to identify absence trends.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Markbook and assessment$q$, $q$Homework assignment, online submission, and a gradebook (Markbook) for recording and reporting assessment results.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Lesson planning tools$q$, $q$Reusable 'Smart Blocks' for rich multimedia lesson plans that can be shared with students and parents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Finance module$q$, $q$Tools for managing school fees and billing workflows within the same platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Communication tools$q$, $q$Internal messaging and notification tools for staff, students, and parents, including a dedicated calendar module.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$24+ core modules$q$, $q$A broad set of built-in modules covering academics, operations, and communication out of the box.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Custom module development$q$, $q$Because the codebase is open source, schools or developers can build additional custom modules tailored to specific workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Completely free and open-source with no per-student licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Highly flexible and extensible thanks to open, modular PHP codebase$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Broad feature set spanning academics, attendance, finance, and communication in one system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Runs on affordable, widely available PHP/MySQL hosting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Popular and well-documented within international and independent school communities$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$No managed SaaS option from the project itself; schools must arrange and pay for hosting separately$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Requires technical setup and maintenance knowledge (or a paid contractor) to run reliably$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Interface and UX are less polished than well-funded commercial school information systems$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Smaller support team compared to commercial SIS vendors, relying heavily on community forums$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Custom modules or heavy customization require developer resources most small schools don't have in-house$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Is Gibbon really free?$q$, $q$Yes, Gibbon's core software is completely free and open source; the only real costs are hosting infrastructure and any optional paid support or customization.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Who created Gibbon?$q$, $q$Gibbon was founded in October 2010 by educator Ross Parker, who remains the project's founder and lead developer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$What kind of server does Gibbon require?$q$, $q$Gibbon runs on a standard PHP and MySQL/MariaDB web server, similar to hosting requirements for platforms like WordPress.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Does Gibbon include attendance and gradebook features?$q$, $q$Yes, attendance tracking and a full markbook/assessment gradebook are among Gibbon's roughly two dozen core modules.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Can schools customize Gibbon?$q$, $q$Yes, because Gibbon is open source, schools with developer resources (or hired contractors) can build custom modules on top of the core platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$How is Gibbon different from commercial school management systems?$q$, $q$Unlike commercial SIS platforms like PowerSchool or Veracross, Gibbon has no licensing fees; schools instead pay only for their own hosting and optional support.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$International and independent schools$q$, $q$Managing student records, attendance, and communication for schools operating outside large commercial SIS budgets.$q$, $q$International and independent school administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Home-school and small education networks$q$, $q$Running lightweight but complete school administration for home-school co-ops or small learning centers.$q$, $q$Home-school networks and small education providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Budget-constrained and nonprofit education programs$q$, $q$Providing full school management capability without per-student licensing costs.$q$, $q$Nonprofit and refugee education programs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Gibbon Core (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","24+ core modules","Unlimited students and staff","Community support forum and documentation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Hosting (third-party, variable)$q$, $q$Varies by provider$q$, $q$Monthly or annual$q$, NULL, $q$["PHP/MySQL web hosting","Cost depends on number of users and usage","Optional managed hosting providers available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$Paid support / custom development$q$, $q$Contact for pricing$q$, $q$Project-based$q$, NULL, $q$["Installation assistance","Custom module development","Ongoing maintenance support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gibbon is a free, open-source school management platform founded in October 2010 by educator and technologist Ross Parker, now in its 30th major version after fifteen years of continuous development.$q$, $q$It covers the full operational surface of running a school, from student records and attendance to gradebooks, finance, and communication, and runs on a standard PHP/MySQL web stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gibbon ships with roughly two dozen core modules spanning student management, attendance, assessment and markbooks, lesson planning, finance, and internal communication.$q$, $q$Distinctive tools include the Fast Student Finder for quickly surfacing academic, behavioral, medical, and SEN alerts, and Smart Blocks for reusable lesson planning.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gibbon's software is entirely free and open source with no freemium or SaaS licensing model; core features will always remain free according to the project.$q$, $q$The real cost to a school is web hosting (self-managed or via a third-party provider) plus optional paid support or custom development services.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23a978e7-3e1a-4d34-b4db-5a37d2dff05c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Layer-based compositing$q$, $q$Full layer support with masks, blend modes, and groups for complex image composition.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Advanced selection tools$q$, $q$Bezier-curve path tools, magic wand, and other precision selection methods for detailed editing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$150+ built-in filters and effects$q$, $q$A large library of native filters for blurring, distortion, artistic effects, and color manipulation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Non-destructive editing (3.0+)$q$, $q$GIMP 3.0 introduced non-destructive adjustment layers and effects, closing a long-standing gap with commercial editors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Scripting and automation$q$, $q$Script-Fu (Scheme), Python, Perl, and Tcl support for batch processing and custom tool automation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Broad file format support$q$, $q$Native XCF format plus import/export for JPEG, PNG, WebP, GIF, TIFF, and Photoshop PSD files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Cross-platform availability$q$, $q$Native builds for Windows, macOS, and Linux/BSD, maintained by the open-source community.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Plug-in ecosystem$q$, $q$An extensible plug-in architecture supporting large third-party filter packs like G'MIC.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Completely free with no subscriptions, licensing fees, or feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Professional-grade feature set comparable to commercial editors like Photoshop$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Fully open source, auditable, and cross-platform (Windows, macOS, Linux)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Highly extensible through scripting (Python, Script-Fu) and a large plug-in ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Nearly 30 years of continuous development and an active, stable community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Steeper learning curve and less polished UX than modern commercial competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Non-destructive editing arrived only with version 3.0 in 2025, decades after commercial rivals offered it$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$No official technical support beyond community forums and documentation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Some professional workflows (advanced CMYK printing, certain PSD features) are less mature than Photoshop's$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Interface conventions can feel unfamiliar to users coming directly from Adobe products$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Is GIMP really free?$q$, $q$Yes, GIMP is completely free to download, use, and modify under the GNU General Public License v3 or later, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Who created GIMP?$q$, $q$GIMP was created in 1995 by Spencer Kimball and Peter Mattis as a class project at UC Berkeley, later becoming affiliated with the GNU Project with Richard Stallman's approval.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Is GIMP a good alternative to Photoshop?$q$, $q$GIMP is widely considered the leading free alternative to Photoshop, offering a comparable professional feature set, though with a steeper learning curve and a different interface.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$What platforms does GIMP support?$q$, $q$GIMP runs natively on Windows, macOS, and Linux/BSD, with community-maintained builds available for most major operating systems.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Does GIMP support non-destructive editing?$q$, $q$Yes, full non-destructive editing was introduced in GIMP 3.0, released in March 2025.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Can GIMP open Photoshop PSD files?$q$, $q$Yes, GIMP supports importing and exporting Photoshop PSD files, though very advanced PSD-specific features may not fully translate.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Photo retouching and editing$q$, $q$Correcting color, removing blemishes, and compositing photographs without a paid subscription.$q$, $q$Hobbyist and semi-professional photographers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Digital art and illustration$q$, $q$Creating digital paintings and graphics using GIMP's brush, layer, and selection tools.$q$, $q$Digital artists and illustrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$Batch image processing and automation$q$, $q$Using Script-Fu or Python scripting to automate repetitive editing tasks across many files.$q$, $q$Developers and technical users needing image automation$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$GIMP (all platforms)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set with no restrictions","Windows, macOS, and Linux/BSD support","GNU GPL v3+ open-source license","Community documentation and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GIMP began in 1995 as a UC Berkeley class project by Spencer Kimball and Peter Mattis and became the GNU Image Manipulation Program after Richard Stallman approved its GNU affiliation in 1997.$q$, $q$Nearly three decades later it remains a fully free, open-source, cross-platform raster image editor maintained entirely by volunteer developers, with GIMP 3.0 (2025) finally delivering full non-destructive editing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GIMP offers layer-based compositing, advanced Bezier-path selections, roughly 150 built-in filters, and support for native XCF plus common formats like JPEG, PNG, WebP, TIFF, and Photoshop PSD files.$q$, $q$Its scripting system supports Script-Fu, Python, Perl, and Tcl for automation, and its plug-in architecture has produced a large ecosystem of third-party extensions such as the G'MIC filter collection.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GIMP is completely free under the GNU General Public License v3 or later, with no paid tiers, subscriptions, or feature restrictions of any kind.$q$, $q$It is sustained by volunteer development and community donations rather than commercial licensing, in direct contrast to Adobe Photoshop's subscription-based Creative Cloud model.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05fd9154-b81e-4108-87a9-fd64b03f828c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Large file management without repository bloat$q$, $q$Tracks large files via lightweight pointer symlinks in Git while storing actual content separately.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Fully distributed architecture$q$, $q$No central server required; any clone can hold a full or partial copy of the data with peer-to-peer synchronization.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Location tracking$q$, $q$UUID-based tracking of exactly which repository clones hold copies of which files, useful for verifying backup redundancy.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Partial checkouts and selective sync$q$, $q$Clone repository structure and history without downloading every large file, or sync only files relevant to a given machine.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Broad storage backend support$q$, $q$Special remotes system supports S3, Google Cloud, Backblaze B2, rsync, external drives, and other git-annex repositories as storage targets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Content-addressable storage$q$, $q$Files are referenced by cryptographic checksum keys, enabling deduplication and integrity verification.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Cross-platform packaging$q$, $q$Available on major Linux distributions, BSDs, macOS, Windows, and Android.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$git-annex assistant$q$, $q$Kickstarter-funded automated synchronization mode offering Dropbox-like background syncing on top of git-annex's core.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Completely free and open source with no licensing costs or storage quotas imposed by the project$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Fully distributed design with no dependency on a single central server or commercial host$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Far more powerful than simpler large-file tools like Git LFS (location tracking, partial checkouts, selective sync)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Battle-tested and actively maintained for over a decade, widely used in scientific computing via DataLad$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Broad cross-platform support across Linux, BSD, macOS, Windows, and Android$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Steep learning curve and command-line-first design compared to turnkey sync tools like Dropbox$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$No formal company or paid support plan; help comes primarily from documentation and community channels$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Less widely adopted and less simple to onboard than GitHub's Git LFS for basic use cases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Symlink-based workflow can be confusing for users unfamiliar with how it alters the working tree$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Requires careful configuration to manage storage backends and replication rules correctly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Is git-annex free to use?$q$, $q$Yes, git-annex is completely free and open source, licensed under GPL-3+ with AGPL-3+ for some networked components, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Who created git-annex?$q$, $q$git-annex was created by independent free-software developer Joey Hess, with development starting in 2010.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$How is git-annex different from Git LFS?$q$, $q$git-annex is fully distributed with no required central server and supports advanced features like location tracking and partial checkouts, while Git LFS is simpler but depends on a central LFS server with storage/bandwidth quotas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$What programming language is git-annex written in?$q$, $q$git-annex is written in Haskell.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$What is git-annex commonly used for?$q$, $q$It's commonly used to version and distribute very large files and datasets, notably as the storage engine behind DataLad in scientific computing, as well as for personal media libraries and decentralized backups.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Does git-annex require a central server?$q$, $q$No, git-annex is fully distributed; any repository clone can hold a full or partial copy of the data without a required central hosting server.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Scientific dataset versioning$q$, $q$Versioning and distributing large research datasets, notably as the engine behind the DataLad project used in computational neuroscience.$q$, $q$Researchers and scientific computing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Decentralized backups and archives$q$, $q$Building resilient, multi-copy backup systems with verifiable location tracking across many storage locations.$q$, $q$System administrators and digital archivists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$Personal large-media synchronization$q$, $q$Syncing large personal media libraries (photos, video) across multiple devices without relying on a single commercial cloud provider.$q$, $q$Privacy-focused power users and photographers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$git-annex (all platforms)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set with no restrictions","GPL-3+/AGPL-3+ open-source license","Cross-platform packages (Linux, BSD, macOS, Windows, Android)","Community documentation and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$git-annex is a free, open-source extension to Git created by independent developer Joey Hess starting in 2010, designed to manage very large files without storing their content in Git's own history.$q$, $q$Written in Haskell and funded in part through 2012-2013 and 2013-2014 crowdfunding campaigns, it remains an independently maintained project rather than a commercial product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$git-annex replaces large files with lightweight symlinks or pointer files tracked by Git, while actual content lives in a separate content-addressable store, locally or on remote backends like S3, rsync targets, or other git-annex clones.$q$, $q$Distinctive capabilities include fully distributed operation with no required central server, UUID-based location tracking of which repository copies hold which files, and support for partial checkouts and selective syncing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$git-annex is entirely free and open source under GPL-3+ (with AGPL-3+ for certain networked components), with no commercial licensing tiers or paid support plans offered by the project.$q$, $q$There is no company behind it; it is sustained by its original author and volunteer contributors rather than subscription or licensing revenue.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('89ceb22c-3639-45b9-b003-00aa1f289c00', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Block-based visual editor$q$, $q$A modern, collaborative editing experience for authoring documentation without needing to write raw Markdown.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Git sync (GitHub/GitLab)$q$, $q$Two-way synchronization with Git repositories for documentation-as-code workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$API playgrounds$q$, $q$Interactive, testable API reference documentation generated alongside narrative content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Change requests$q$, $q$Pull-request-style review and approval workflow for proposed documentation edits.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$AI Assistant and AI search$q$, $q$An AI agent that answers questions grounded in a team's own documentation content, plus AI-powered search.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Real-time collaboration$q$, $q$Multiple team members editing documentation simultaneously, similar to Google Docs-style collaboration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Custom domains and branding$q$, $q$White-labeled documentation sites with custom domains, fonts, and branding on paid tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Authenticated/gated access$q$, $q$Restrict documentation access to logged-in or authorized users on higher tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Combines Git-based version control with an easy-to-use visual editor for both technical and non-technical writers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Strong built-in API reference and playground tooling for developer documentation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Increasingly capable AI search, writing, and question-answering features grounded in a team's own docs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Polished, professional out-of-the-box design for published documentation sites$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Generous free tier for a single basic site$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Per-site pricing can get expensive quickly for organizations needing multiple documentation sites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Additional per-user charges stack on top of the base site price at every paid tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Advanced AI features are reserved for the pricier Ultimate and Enterprise tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Free tier excludes custom domains and real-time collaboration, limiting its use for public-facing docs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Smaller ecosystem/plugin community compared to open-source alternatives like Docusaurus$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Is GitBook free to use?$q$, $q$Yes, GitBook offers a Free tier for a single site with basic editing, Git sync, and API playgrounds, though it excludes custom domains and real-time collaboration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$How much does GitBook cost?$q$, $q$Paid plans start at $65 per site per month (Premium, billed annually) and go up to $249 per site per month (Ultimate), plus $12 per additional user per month on both tiers; Enterprise is custom-priced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Who founded GitBook?$q$, $q$GitBook was founded in 2014 by Aaron O'Mullan and Samy Pesse, and is headquartered in Lyon, France.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Does GitBook support Git-based workflows?$q$, $q$Yes, GitBook supports two-way sync with GitHub and GitLab repositories for documentation-as-code workflows alongside its visual editor.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Does GitBook have AI features?$q$, $q$Yes, GitBook includes AI-powered search, writing assistance, and an AI Assistant agent that can answer questions based on a team's own documentation, with more advanced AI tools on the Ultimate and Enterprise tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$What are the main alternatives to GitBook?$q$, $q$Common alternatives include Docusaurus, MkDocs, ReadMe, Notion, Confluence, and Stoplight, depending on whether the priority is developer-first docs-as-code, general knowledge bases, or API documentation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$API and developer documentation$q$, $q$Publishing interactive API references and developer guides synced with a GitHub or GitLab repository.$q$, $q$Developer relations and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Product documentation and help centers$q$, $q$Building customer-facing product documentation with collaborative editing and analytics.$q$, $q$Product and technical writing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Internal knowledge bases$q$, $q$Maintaining internal engineering or company documentation with gated, authenticated access.$q$, $q$Internal IT and operations teams at larger companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Free$q$, $q$$0/site/month$q$, $q$N/A$q$, NULL, $q$["1 site, 1 free user","Block-based visual editor","GitHub/GitLab sync","API playgrounds","Preview deployments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Premium$q$, $q$$65/site/month + $12/additional user/month$q$, $q$Annual (14-day free trial)$q$, NULL, $q$["Team collaboration with change requests","AI search and writing/editing tools","Custom domain and advanced branding","Analytics and user feedback","Real-time collaboration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Ultimate$q$, $q$$249/site/month + $12/additional user/month$q$, $q$Annual (14-day free trial)$q$, NULL, $q$["Full AI Assistant with customization","AI Insights and unlimited GitBook Agent","Unlimited adaptive content","Authenticated access","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Invoice-based$q$, NULL, $q$["SAML SSO","White-glove migration","Dedicated account manager","Custom integrations","Legal and security reviews"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GitBook was founded in 2014 by Aaron O'Mullan and Samy Pesse in Lyon, France, originally built around Git-based, Markdown-driven documentation workflows.$q$, $q$It has since evolved into an AI-native documentation platform combining a block-based visual editor, Git sync, API reference tooling, and AI search, writing, and question-answering features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include a collaborative block-based editor, GitHub/GitLab sync, change requests (pull-request-style content review), and built-in API playgrounds for interactive API reference docs.$q$, $q$Higher tiers add an AI Assistant grounded in a team's own documentation, AI Insights, adaptive content, authenticated/gated access, and enterprise features like SAML SSO.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3af57a6b-aa7b-403a-a094-3150492f8e93', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GitBook prices per published site: Free for a single basic site, Premium at $65/site/month, and Ultimate at $249/site/month (both billed annually, plus $12 per additional user/month).$q$, $q$A custom-priced Enterprise tier adds SSO, white-glove migration, and dedicated support for larger organizations.$q$]::text[], 2);
