INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Git code hosting$q$, $q$Full Git repository hosting with unlimited users and repositories in the free self-hosted core.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Issue tracking and pull requests$q$, $q$Built-in issue tracker and pull request review workflow for collaborative development.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Gitea Actions (CI/CD)$q$, $q$Native CI/CD system modeled after GitHub Actions workflow syntax for automated builds and tests.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Kanban-style project boards$q$, $q$Lightweight project management boards for tracking issues and tasks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Package registry$q$, $q$Built-in registry supporting multiple package formats for hosting software packages alongside code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Wikis$q$, $q$Integrated wiki functionality for project documentation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Lightweight, low-resource footprint$q$, $q$Written in Go, designed to run efficiently on minimal hardware including a Raspberry Pi.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$SAML SSO and audit logs (Enterprise)$q$, $q$Enterprise-tier features for organizations needing single sign-on and compliance auditing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Free, MIT-licensed self-hosted core with no artificial limits on users or repositories$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Very lightweight and resource-efficient compared to heavier alternatives like self-hosted GitLab$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Built-in CI/CD (Gitea Actions), package registry, and project boards without extra tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Managed Gitea Cloud option removes the need to operate infrastructure directly$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Active development and cross-platform support (Linux, macOS, Windows, BSD)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$2022 commercialization by Gitea Limited caused community controversy and a competing Forgejo fork$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Enterprise and Cloud pricing require a one-year commitment for online payment customers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Smaller third-party integration ecosystem than GitHub or GitLab$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Some advanced compliance and governance features are gated behind the paid Enterprise tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Less mature built-in CI/CD ecosystem than GitLab's more established pipelines$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Is Gitea free to use?$q$, $q$Yes, the self-hosted, MIT-licensed Gitea core is completely free with unlimited users and repositories; paid Enterprise and Cloud tiers add support, SSO, and managed hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$How is Gitea related to Gogs?$q$, $q$Gitea began as a fork of Gogs in November 2016, created to move toward a community-driven governance model instead of single-maintainer control.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$What is the difference between Gitea and Forgejo?$q$, $q$Forgejo is a fork of Gitea created by Codeberg in late 2022 in response to Gitea Limited's commercialization, positioned as a community-owned alternative that avoids proprietary commercial offerings.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$How much does Gitea Cloud cost?$q$, $q$Gitea Cloud and Enterprise pricing runs roughly $9.50 to $19 per user per month depending on plan, with additional object storage billed at about $10 per 100GB; a 30-day free trial is available.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$What programming language is Gitea written in?$q$, $q$Gitea is written primarily in Go with a TypeScript-based frontend.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Can Gitea run on low-resource hardware?$q$, $q$Yes, Gitea is deliberately lightweight and can run on very modest hardware, including devices like a Raspberry Pi.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Self-hosted code hosting for small teams$q$, $q$Running a free, lightweight Git server for internal projects without per-user licensing costs.$q$, $q$Small development teams and individual developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Resource-constrained self-hosting$q$, $q$Hosting a Git service on minimal hardware such as a home server or Raspberry Pi.$q$, $q$Self-hosting enthusiasts and homelab users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Enterprise compliance and managed hosting$q$, $q$Using Gitea Enterprise or Gitea Cloud for SSO, audit logs, and fully managed infrastructure.$q$, $q$Organizations needing compliance features without heavier platforms like GitLab$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Code hosting, issue tracking, pull requests","Gitea Actions CI/CD","Package registry","Unlimited users and repositories","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Enterprise (self-managed)$q$, $q$$9.50-$19/user/month$q$, $q$Monthly (1-year commitment for online payment)$q$, NULL, $q$["All Open Source features","SAML SSO integration","Audit logs","Kubernetes autoscaling CI/CD runners","Priority security notifications","Email/online support with SLA"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$Gitea Cloud$q$, $q$From about $9.50/user/month$q$, $q$Monthly or annual (30-day free trial)$q$, NULL, $q$["Fully managed Gitea instance","Choice of cloud provider and region","Unlimited network traffic","Zero-maintenance automatic upgrades","Add-on storage at ~$10/100GB"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gitea is a lightweight, MIT-licensed, self-hostable Git service that forked from Gogs in November 2016 to establish a community-driven governance model, shipping its first 1.0 release that December.$q$, $q$In October 2022, maintainers Lunny Xiao and Matti Ranta founded the for-profit Gitea Limited in Hamburg, Germany, to offer commercial Enterprise and Cloud products, a move that prompted Codeberg to create the community-governed Forgejo fork.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free, self-hosted MIT-licensed core includes code hosting, issue tracking, pull requests, a kanban-style project board, wikis, Gitea Actions CI/CD, and a package registry, with unlimited users and repositories.$q$, $q$Written in Go with a TypeScript frontend, Gitea is deliberately lightweight enough to run on very modest hardware such as a Raspberry Pi.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source core is entirely free to self-host with no user or repository limits under the MIT license.$q$, $q$Gitea Enterprise (self-managed) is priced at roughly $9.50-$19 per user per month, while Gitea Cloud offers fully managed hosting with a 30-day free trial and additional storage billed at about $10 per 100GB.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b8e10e1d-f374-4ec0-aa21-3a07fe66eae5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
